queries.sparql:
PREFIX : <http://ambrosia.example.org/airport#>
PREFIX p: <http://ambrosia.example.org/airport/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?o0 WHERE {
  {
    ?hotel a :Hotels .
    ?hotel p:Airport_Hotel ?airport_hotel .
    BIND(?airport_hotel AS ?o0)
  }
  UNION
  {
    ?sleeppod a :SleepPod .
    ?sleeppod p:Sleep_Pod ?sleep_pod .
    ?sleeppod p:Price ?price_f .
    FILTER((STR(?price_f) = "150" || STR(?price_f) = "150.0"))
    BIND(?sleep_pod AS ?o0)
  }
}

